Context.miscCode:
	function  checkSolicitorForSubject(){
    	solExists = false;     
        litPartiesXPath = "/params/param/ds/ManageCase/Parties/LitigiousParty[./TypeCode = 'CREDITOR']";
        litPartiesObtained =   WPU.getNode(litPartiesXPath,null);                    
        if(litPartiesObtained != null){
        	solicitorIdNode = litPartiesObtained.selectSingleNode("SolicitorSurrogateId");
       		sol = XML.getNodeTextContent(solicitorIdNode);
            if(sol != null) { solExists = true; } }
        return solExists; }

Javascript.miscCode:
	function  checkSolicitorForSubject(){
    	solExists = false;     
        litPartiesXPath = "/params/param/ds/ManageCase/Parties/LitigiousParty[./TypeCode = 'DEBTOR']";
        litPartiesObtained =   WPU.getNode(litPartiesXPath,null);                    
        if(litPartiesObtained != null){
        	solicitorIdNode = litPartiesObtained.selectSingleNode("SolicitorSurrogateId");
            if(solicitorIdNode != null){
            	solExists = true; } }
        return solExists; }
